@Service
class SamlCredentialService {

    private final SamlProperties properties;

    public SamlCredentialService(SamlProperties properties) {
        this.properties = properties;
    }

    public BasicX509Credential getSpCredential() {
        try {
            PrivateKey privateKey = readPrivateKey(properties.getSpPrivateKey());
            JcaX509Certificate cert = readCertificate(properties.getSpCertificate());
            BasicX509Credential credential = new BasicX509Credential(cert, privateKey);
            credential.setEntityId(properties.getSpEntityId());
            return credential;
        } catch (Exception e) {
            throw new IllegalStateException("Failed to load SP credential", e);
        }
    }

    public BasicX509Credential getIdpCredential() {
        try {
            JcaX509Certificate cert = readCertificate(properties.getIdpCertificate());
            BasicX509Credential credential = new BasicX509Credential(cert);
            credential.setEntityId(properties.getIdpEntityId());
            return credential;
        } catch (Exception e) {
            throw new IllegalStateException("Failed to load IdP credential", e);
        }
    }

    private PrivateKey readPrivateKey(Resource resource) throws Exception {
        String pem = new String(StreamUtils.copyToByteArray(resource.getInputStream()), StandardCharsets.UTF_8);
        pem = pem.replace("-----BEGIN PRIVATE KEY-----", "")
                 .replace("-----END PRIVATE KEY-----", "")
                 .replaceAll("\\s", "");
        byte[] bytes = Base64.getDecoder().decode(pem);
        return KeyFactory.getInstance("RSA").generatePrivate(new PKCS8EncodedKeySpec(bytes));
    }

    private JcaX509Certificate readCertificate(Resource resource) throws Exception {
        try (InputStream is = resource.getInputStream()) {
            return (JcaX509Certificate) CertificateFactory.getInstance("X.509").generateCertificate(is);
        }
    }
}

