@Service
class SamlMetadataService {

    private final SamlProperties properties;
    private final SamlCredentialService credentialService;

    public SamlMetadataService(SamlProperties properties, SamlCredentialService credentialService) {
        this.properties = properties;
        this.credentialService = credentialService;
    }

    public String generateMetadata() {
        try {
            XMLObjectBuilderFactory bf = XMLObjectProviderRegistrySupport.getBuilderFactory();

            EntityDescriptor entityDescriptor = (EntityDescriptor) bf
                    .getBuilder(EntityDescriptor.DEFAULT_ELEMENT_NAME)
                    .buildObject(EntityDescriptor.DEFAULT_ELEMENT_NAME);
            entityDescriptor.setEntityID(properties.getSpEntityId());

            SPSSODescriptor spDescriptor = (SPSSODescriptor) bf
                    .getBuilder(SPSSODescriptor.DEFAULT_ELEMENT_NAME)
                    .buildObject(SPSSODescriptor.DEFAULT_ELEMENT_NAME);
            spDescriptor.addSupportedProtocol(SAMLConstants.SAML20P_NS);
            spDescriptor.setAuthnRequestsSigned(true);
            spDescriptor.setWantAssertionsSigned(true);

            KeyDescriptor signingKeyDescriptor = (KeyDescriptor) bf
                    .getBuilder(KeyDescriptor.DEFAULT_ELEMENT_NAME)
                    .buildObject(KeyDescriptor.DEFAULT_ELEMENT_NAME);
            signingKeyDescriptor.setUse(UsageType.SIGNING);
            signingKeyDescriptor.setKeyInfo(buildKeyInfo(credentialService.getSpCredential()));
            spDescriptor.getKeyDescriptors().add(signingKeyDescriptor);

            KeyDescriptor encryptionKeyDescriptor = (KeyDescriptor) bf
                    .getBuilder(KeyDescriptor.DEFAULT_ELEMENT_NAME)
                    .buildObject(KeyDescriptor.DEFAULT_ELEMENT_NAME);
            encryptionKeyDescriptor.setUse(UsageType.ENCRYPTION);
            encryptionKeyDescriptor.setKeyInfo(buildKeyInfo(credentialService.getSpCredential()));
            spDescriptor.getKeyDescriptors().add(encryptionKeyDescriptor);

            AssertionConsumerService acs = (AssertionConsumerService) bf
                    .getBuilder(AssertionConsumerService.DEFAULT_ELEMENT_NAME)
                    .buildObject(AssertionConsumerService.DEFAULT_ELEMENT_NAME);
            acs.setBinding(SAMLConstants.SAML2_POST_BINDING_URI);
            acs.setLocation(properties.getAcsUrl());
            acs.setIndex(0);
            acs.setIsDefault(true);
            spDescriptor.getAssertionConsumerServices().add(acs);

            SingleLogoutService slo = (SingleLogoutService) bf
                    .getBuilder(SingleLogoutService.DEFAULT_ELEMENT_NAME)
                    .buildObject(SingleLogoutService.DEFAULT_ELEMENT_NAME);
            slo.setBinding(SAMLConstants.SAML2_POST_BINDING_URI);
            slo.setLocation(properties.getSloUrl());
            spDescriptor.getSingleLogoutServices().add(slo);

            NameIDFormat nif = (NameIDFormat) bf
                    .getBuilder(NameIDFormat.DEFAULT_ELEMENT_NAME)
                    .buildObject(NameIDFormat.DEFAULT_ELEMENT_NAME);
            nif.setURI(NameIDType.PERSISTENT);
            spDescriptor.getNameIDFormats().add(nif);

            entityDescriptor.getRoleDescriptors().add(spDescriptor);

            return XMLObjectSupport.marshallToOutputString(entityDescriptor);
        } catch (Exception e) {
            throw new IllegalStateException("Failed to generate metadata", e);
        }
    }

    private KeyInfo buildKeyInfo(BasicX509Credential credential) throws Exception {
        BasicKeyInfoGeneratorFactory keyInfoGeneratorFactory = new BasicKeyInfoGeneratorFactory();
        keyInfoGeneratorFactory.setEmitX509Certificate(true);
        return keyInfoGeneratorFactory.newInstance().generate(credential);
    }
}

@RestController
@RequestMapping("/saml")
class SamlController {

    private final SamlRequestService samlRequestService;
    private final SamlResponseService samlResponseService;
    private final SamlMetadataService samlMetadataService;

    public SamlController(SamlRequestService samlRequestService,
                          SamlResponseService samlResponseService,
                          SamlMetadataService samlMetadataService) {
        this.samlRequestService = samlRequestService;
        this.samlResponseService = samlResponseService;
        this.samlMetadataService = samlMetadataService;
    }

    @GetMapping("/login")
    public void login(HttpServletResponse response) throws IOException {
        AuthnRequest request = samlRequestService.buildAuthnRequest();
        String xml = XMLObjectSupport.marshallToOutputString(request);
        String samlRequest = Base64.getEncoder().encodeToString(xml.getBytes(StandardCharsets.UTF_8));
        String redirectUrl = request.getDestination() + "?SAMLRequest=" + java.net.URLEncoder.encode(samlRequest, StandardCharsets.UTF_8);
        response.sendRedirect(redirectUrl);
    }

    @PostMapping(value = "/acs", produces = MediaType.APPLICATION_JSON_VALUE)
    public SamlUser acs(HttpServletRequest request) {
        return samlResponseService.processResponse(request);
    }

    @GetMapping(value = "/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public String metadata() {
        return samlMetadataService.generateMetadata();
    }
}